function detectSixDestructions(pillars) {
  const branches = [pillars.year.branch, pillars.month.branch, pillars.day.branch, pillars.hour.branch];
  const destructions = [];
  for (const pair of DESTRUCTION_PAIRS) {
    if (branches.includes(pair.branches[0]) && branches.includes(pair.branches[1])) {
      destructions.push(pair);
    }
  }
  return destructions;
}
